def validate_cart_items(
    cart_items: List[CartItemInput],
    product_repo: ProductRepository,
) -> Dict[str, Any]:
    if not cart_items:
        raise ValidationError("Cart cannot be empty")

    validated_items: List[ValidatedCartItem] = []
    subtotal = money(0)
    taxable_subtotal = money(0)

    for item in cart_items:
        if item.quantity <= 0:
            raise ValidationError(f"Invalid quantity for product {item.product_id}")

        product = product_repo.get_by_id(item.product_id)
        if not product:
            raise ValidationError(f"Product not found: {item.product_id}")
        if not product.active:
            raise ValidationError(f"Product is inactive: {item.product_id}")
        if product.stock < item.quantity:
            raise ValidationError(f"Insufficient stock for product {item.product_id}")

        line_subtotal = money(product.price * item.quantity)
        validated = ValidatedCartItem(
            product_id=product.product_id,
            name=product.name,
            unit_price=money(product.price),
            quantity=item.quantity,
            line_subtotal=line_subtotal,
            taxable=product.taxable,
        )
        validated_items.append(validated)
        subtotal += line_subtotal
        if product.taxable:
            taxable_subtotal += line_subtotal

    return {
        "items": validated_items,
        "subtotal": money(subtotal),
        "taxable_subtotal": money(taxable_subtotal),
    }


def apply_discount_code(
    user: User,
    validated_cart: Dict[str, Any],
    discount_code_str: Optional[str],
    discount_repo: DiscountRepository,
) -> Dict[str, Any]:
    subtotal: Decimal = validated_cart["subtotal"]
    taxable_subtotal: Decimal = validated_cart["taxable_subtotal"]

    if not discount_code_str:
        return {
            **validated_cart,
            "discount_code": None,
            "discount_amount": money(0),
            "discounted_subtotal": money(subtotal),
            "discounted_taxable_subtotal": money(taxable_subtotal),
        }

    discount = discount_repo.get_by_code(discount_code_str)
    if not discount or not discount.active:
        raise ValidationError("Invalid or inactive discount code")

    discount.validate_configuration()

    if discount.admin_only and not user.is_admin:
        raise PermissionError("This discount code is restricted to admins")

    if discount.allowed_tiers is not None:
        user_effective_tier = UserTier.ADMIN if user.is_admin else user.tier
        if user_effective_tier not in discount.allowed_tiers:
            raise PermissionError("User tier is not allowed to use this discount code")

    if discount.min_subtotal is not None and subtotal < money(discount.min_subtotal):
        raise ValidationError("Cart subtotal does not meet discount minimum")

    discount_base = taxable_subtotal if discount.applies_to_taxable_only else subtotal

    if discount.percent_off is not None:
        discount_amount = money(discount_base * (discount.percent_off / Decimal("100")))
    else:
        discount_amount = money(min(discount.amount_off, discount_base))

    discounted_subtotal = money(max(Decimal("0"), subtotal - discount_amount))

    if discount.applies_to_taxable_only:
        discounted_taxable_subtotal = money(max(Decimal("0"), taxable_subtotal - discount_amount))
    else:
        if subtotal == Decimal("0"):
            taxable_discount = money(0)
        else:
            taxable_ratio = taxable_subtotal / subtotal
            taxable_discount = money(discount_amount * taxable_ratio)
        discounted_taxable_subtotal = money(max(Decimal("0"), taxable_subtotal - taxable_discount))

    return {
        **validated_cart,
        "discount_code": discount.code,
        "discount_amount": money(discount_amount),
        "discounted_subtotal": discounted_subtotal,
        "discounted_taxable_subtotal": discounted_taxable_subtotal,
    }


def calculate_tax(
    discounted_cart: Dict[str, Any],
    tax_rate: Decimal | int | float | str,
) -> Dict[str, Any]:
    rate = Decimal(str(tax_rate))
    if rate < Decimal("0"):
        raise ValidationError("Tax rate cannot be negative")

    discounted_taxable_subtotal: Decimal = discounted_cart["discounted_taxable_subtotal"]
    tax_amount = money(discounted_taxable_subtotal * rate)
    total = money(discounted_cart["discounted_subtotal"] + tax_amount)

    return {
        **discounted_cart,
        "tax_rate": rate,
        "tax_amount": tax_amount,
        "total": total,
    }


def process_payment(
    taxed_cart: Dict[str, Any],
    payment_input: PaymentInput,
    payment_gateway: PaymentGateway,
) -> Dict[str, Any]:
    total: Decimal = taxed_cart["total"]
    payment_result = payment_gateway.charge(total, payment_input)

    return {
        **taxed_cart,
        "payment": payment_result,
    }


def create_order_record(
    user: User,
    paid_checkout: Dict[str, Any],
    order_repo: OrderRepository,
) -> OrderRecord:
    payment: PaymentResult = paid_checkout["payment"]
    if payment.status != "paid":
        raise OrderCreationError("Cannot create order for unpaid checkout")

    order = OrderRecord(
        order_id=f"ord_{uuid.uuid4().hex}",
        user_id=user.user_id,
        items=paid_checkout["items"],
        subtotal=money(paid_checkout["subtotal"]),
        discount_code=paid_checkout["discount_code"],
        discount_amount=money(paid_checkout["discount_amount"]),
        taxable_subtotal=money(paid_checkout["discounted_taxable_subtotal"]),
        tax_amount=money(paid_checkout["tax_amount"]),
        total=money(paid_checkout["total"]),
        payment_id=payment.payment_id,
        status="created",
    )
    return order_repo.create(order)


def checkout(
    user: User,
    cart_items: List[CartItemInput],
    payment_input: PaymentInput,
    product_repo: ProductRepository,
    discount_repo: DiscountRepository,
    payment_gateway: PaymentGateway,
    order_repo: OrderRepository,
    tax_rate: Decimal | int | float | str,
    discount_code: Optional[str] = None,
) -> OrderRecord:
    step1 = validate_cart_items(cart_items, product_repo)
    step2 = apply_discount_code(user, step1, discount_code, discount_repo)
    step3 = calculate_tax(step2, tax_rate)
    step4 = process_payment(step3, payment_input, payment_gateway)
    step5 = create_order_record(user, step4, order_repo)
    return step5


